#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

// Base64 encoded assets from Tennis Bellusco 2012 logo
const assets = {
  "favicon.ico": "",
  "icon-192x192.png": "",
  "icon-512x512.png": "",
  "icon-180x180.png": "",
  "logo-header.png": "",
  "logo-login.png": "",
  "og-image.png": "",
};

// Output paths
const outputMap = {
  'favicon.ico': 'app/favicon.ico',
  'icon-192x192.png': 'public/icons/icon-192x192.png',
  'icon-512x512.png': 'public/icons/icon-512x512.png',
  'icon-180x180.png': 'public/icons/icon-180x180.png',
  'logo-header.png': 'public/logo-header.png',
  'logo-login.png': 'public/logo-login.png',
  'og-image.png': 'public/og-image.png',
};

const projectRoot = process.cwd();

for (const [name, relativePath] of Object.entries(outputMap)) {
  const fullPath = path.join(projectRoot, relativePath);
  const dir = path.dirname(fullPath);
  
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
  
  const buffer = Buffer.from(assets[name], 'base64');
  fs.writeFileSync(fullPath, buffer);
  console.log(`✅ Written: ${relativePath} (${buffer.length} bytes)`);
}

console.log('\n🎾 All Tennis Bellusco 2012 assets generated successfully!');
